var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FACILITY","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"아무도……. 안 다쳤겠지?","JPN":"誰も……怪我してないよね？","ENG":"I hope... no one’s hurt.","TWN":"應該…不會有人受傷吧？"},"stage":{"bg":"FACILITY","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"그래, 괜찮을 거야. 공격성은 최대한 억눌렀으니까……. 나한텐 이게 최선이었어…….","JPN":"そう、きっと大丈夫。攻撃性は最大限抑えたから……私にはそれが最善だった……","ENG":"Yes, I’m sure it will be okay. I made them as docile as possible. That was the best I could do...","TWN":"應…應該不會啦，我已經盡量將攻擊性降到最低了…而且我是有苦衷的……"},"stage":{"bg":"FACILITY","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"드, 드라코! 이제 됐죠?! 어서 날 내보내 줘요!","JPN":"ド、ドラコ！　もういいでしょう？　早く私を出してください！","ENG":"D-Dracasia! Is it over now?! Release me!","TWN":"德…德拉克！可以了吧？！快放我走！"},"stage":{"bg":"FACILITY","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_DARK_NULL","text":{"KOREA":"이런. 기대했던 사람이 아니라 미안하군, 후배님.","JPN":"やれやれ。待っていた人じゃなくてすまないな、後輩くん。","ENG":"I’m sorry, but I’m not the one you’ve been expecting, Lone.","TWN":"哎呀，隆利抱歉，我不是你以為的那個人。"},"stage":{"bg":"FACILITY","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_DARK_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"서…… 선배님……? 여긴 어떻게?","JPN":"せ……先輩……？　どうしてここに？","ENG":"D-Dark? How did you get here?","TWN":"前…前輩…？你怎麼會在這裡？"},"stage":{"bg":"FACILITY","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_DARK_NULL","text":{"KOREA":"시대를 뒤흔드는 대악당인 내가 어째서 여기 왔겠나.","JPN":"時代を揺るがす大悪党である私がどうしてここに来たのかって？","ENG":"What do you think? I am the greatest villain of the age.","TWN":"我這個惡名昭彰的大反派，來這裡還能為什麼？"},"stage":{"bg":"FACILITY","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_DARK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_DARK_NULL","text":{"KOREA":"지독한 악행의 냄새가 풍기고 있었기 때문이지.","JPN":"ひどい悪行の臭いが漂っていたからだ。","ENG":"And I sniffed out a great villainy, which led me here.","TWN":"當然是因為這裡有犯罪的味道囉！"},"stage":{"bg":"FACILITY","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_DARK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"킁, 킁킁!","JPN":"くんくん、くんくん！","ENG":"*Sniff, sniff*","TWN":"嗅…嗅嗅！"},"stage":{"bg":"FACILITY","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_DARK_NULL","text":{"KOREA":"하하. 후배님한테서 난다는 얘기가 아니야.","JPN":"ハハ、君が臭うという話ではない。","ENG":"Hah hah. I didn’t mean you.","TWN":"哈哈，我不是說你的身上有味道啦。"},"stage":{"bg":"FACILITY","slots":{"L":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_DARK_NULL","face":"UNIT_LAUGH"}}}},{"id":"L16_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_DARK_NULL","text":{"KOREA":"냄새의 근원지는 바로 이 시설 자체일세.","JPN":"臭い根源地はまさにこの施設そのものだ。","ENG":"I meant this whole facility.","TWN":"那個犯罪的味道就是從這個地方散發出來的！"},"stage":{"bg":"FACILITY","slots":{"L":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_DARK_NULL","face":"UNIT_PRIDE"}}}},{"id":"L17_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_DARK_NULL","text":{"KOREA":"돈 몇 푼을 위해 주민들의 삶을 빼앗으려고 하는 치졸한 악의가 느껴지는군.","JPN":"お金のために住民の暮らしを奪おうとする稚拙な悪意が感じられるな。","ENG":"I sense a crude evil that wants to ruin the local people’s lives for petty cash.","TWN":"因為一點蠅頭小利，就想把人家趕出家園對不對！"},"stage":{"bg":"FACILITY","slots":{"L":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_DARK_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FACILITY","slots":{"L":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_DARK_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"선배님은……. 정말 모르는 게 없으시네요…….","JPN":"先輩は……本当に何でも知っているんですね……","ENG":"Dark... You really do know everything.","TWN":"前輩…真是什麼都瞞不過你…"},"stage":{"bg":"FACILITY","slots":{"L":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_DARK_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"하지만 전, 결국 선배님의 충고를 따라가지 못했어요.","JPN":"しかし、私は結局、先輩の忠告に従えませんでした。","ENG":"But I failed to follow your advice.","TWN":"但是，我最後還是沒能聽進前輩的忠告。"},"stage":{"bg":"FACILITY","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"여기 온 뒤로, 무서워서 반항도 못해 보고…….","JPN":"ここに来てから、怖くて反抗もできず……","ENG":"Since I was brought here, I’ve been too scared to fight back.","TWN":"我來這裡後，怕到根本不敢反抗…"},"stage":{"bg":"FACILITY","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_DARK_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FACILITY","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_DARK_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"선배님도 역시 이런 제가 한심하시죠?","JPN":"先輩もやっぱりこんな私が情けないと思っているんでしょう？","ENG":"You must think I’m pathetic.","TWN":"前輩也對這樣的我感到很失望吧？"},"stage":{"bg":"FACILITY","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"아무것도 할 줄 모르고, 용기도 없어서 시키는 대로 하는 제가……!","JPN":"何もできず、勇気もなく、言われたとおりにする私が……！","ENG":"An incompetent coward who can’t fight back and does whatever she’s told...","TWN":"什麼都不會，又膽小，人家說什麼我就只能照做……！"},"stage":{"bg":"FACILITY","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};